/****** Object:  View [dbo].[VwProductosPorEncimaDelPrecioPromedio]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VwProductosPorEncimaDelPrecioPromedio]
AS
WITH Promedio AS (
    SELECT CAST(AVG(UnitPrice) AS DECIMAL(18,10)) AS PrecioPromedio
    FROM Products
)
SELECT 
    ROW_NUMBER() OVER (ORDER BY p.UnitPrice ASC) AS Fila,
    p.ProductName AS Producto,
    CAST(p.UnitPrice AS DECIMAL(18,10)) AS Precio,
    pr.PrecioPromedio,
    CAST(p.UnitPrice - pr.PrecioPromedio AS DECIMAL(18,10)) AS Diferencia,
    CAST((p.UnitPrice - pr.PrecioPromedio) / pr.PrecioPromedio AS DECIMAL(18,10)) AS PorcentajeSobrePromedio,
    c.CategoryName AS Categoria,
    s.CompanyName AS Proveedor
FROM Products p
CROSS JOIN Promedio pr
INNER JOIN Categories c ON p.CategoryID = c.CategoryID
INNER JOIN Suppliers s ON p.SupplierID = s.SupplierID
WHERE p.UnitPrice > pr.PrecioPromedio;
GO
