/****** Object:  View [dbo].[Product Sales for 1997]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

create view [dbo].[Product Sales for 1997] AS
SELECT Categories.CategoryName, Products.ProductName, 
Sum(CONVERT(money,("Order Details".UnitPrice*Quantity*(1-Discount)/100))*100) AS ProductSales
FROM (Categories INNER JOIN Products ON Categories.CategoryID = Products.CategoryID) 
	INNER JOIN (Orders 
		INNER JOIN "Order Details" ON Orders.OrderID = "Order Details".OrderID) 
	ON Products.ProductID = "Order Details".ProductID
WHERE (((Orders.ShippedDate) Between '19970101' And '19971231'))
GROUP BY Categories.CategoryName, Products.ProductName
GO
/****** Object:  View [dbo].[VwClientesProveedores]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[VwClientesProveedores]
AS
SELECT 
    c.CompanyName, 
    c.ContactTitle + ', ' + c.ContactName AS Contact, 
    'Cliente' AS Relation, 
    c.Address, 
    c.City, 
    c.Region, 
    c.PostalCode, 
    c.Country, 
    c.Phone, 
    c.Fax
FROM Customers c

UNION ALL

SELECT 
    s.CompanyName, 
    s.ContactTitle + ', ' + s.ContactName AS Contact, 
    'Proveedor' AS Relation, 
    s.Address, 
    s.City, 
    s.Region, 
    s.PostalCode, 
    s.Country, 
    s.Phone, 
    s.Fax
FROM Suppliers s;
GO
