/****** Object:  View [dbo].[VwProductosPorCategoriaListado]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VwProductosPorCategoriaListado]
AS
SELECT dbo.Categories.CategoryName, dbo.Products.ProductName, dbo.Products.ProductID, dbo.Products.QuantityPerUnit, dbo.Products.UnitPrice, dbo.Products.UnitsInStock, dbo.Products.UnitsOnOrder, dbo.Products.ReorderLevel, 
                  dbo.Products.Discontinued, dbo.Suppliers.CompanyName
FROM     dbo.Suppliers RIGHT OUTER JOIN
                  dbo.Products ON dbo.Suppliers.SupplierID = dbo.Products.SupplierID RIGHT OUTER JOIN
                  dbo.Categories ON dbo.Products.CategoryID = dbo.Categories.CategoryID
GO
/****** Object:  View [dbo].[VwCategoriasConProductos]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE VIEW [dbo].[VwCategoriasConProductos]
AS
SELECT dbo.Categories.CategoryName, dbo.Products.ProductName, dbo.Products.ProductID, dbo.Products.QuantityPerUnit, dbo.Products.UnitPrice, dbo.Products.UnitsInStock, dbo.Products.UnitsOnOrder, dbo.Products.ReorderLevel, 
                  dbo.Products.Discontinued, dbo.Suppliers.CompanyName
FROM     dbo.Suppliers RIGHT OUTER JOIN
                  dbo.Products ON dbo.Suppliers.SupplierID = dbo.Products.SupplierID RIGHT OUTER JOIN
                  dbo.Categories ON dbo.Products.CategoryID = dbo.Categories.CategoryID
GO
