/****** Object:  StoredProcedure [dbo].[SpCategoriaActualizar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpCategoriaActualizar]
	@CategoryID int,
	@CategoryName nvarchar(15),
	@Description ntext,
	@Picture image,
	@RowVersion binary(8)
AS
BEGIN
	SET NOCOUNT ON;
	-- Verificar si existe el empleado
    IF NOT EXISTS (SELECT 1 FROM Categories WHERE @CategoryID = @CategoryID)
    BEGIN
        RETURN -1; -- No existe el empleado
    END
	UPDATE Categories 
	SET	CategoryName=@CategoryName,
		Description=@Description,
		--Photo=@Foto
		Picture = CASE 
                WHEN @CategoryID <= 8 THEN Picture  -- conserva la foto existente
                ELSE @Picture                -- actualiza con el parámetro
                END
	WHERE  CategoryID = @CategoryID AND RowVersion = @RowVersion;
	DECLARE @rows int = @@ROWCOUNT;
	IF @rows = 0
        RETURN -2; -- Modificado por otro usuario
    ELSE
        RETURN @rows; -- Éxito
END
GO
/****** Object:  StoredProcedure [dbo].[SpCategoriaBuscar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpCategoriaBuscar]
	@IdIni int,
	@IdFin int,
	@CategoryName nvarchar(15)
AS
BEGIN
	SELECT *
	FROM Categories
	WHERE
	(@IdIni = 0 OR CategoryID BETWEEN @IdIni AND @IdFin) AND
	(@CategoryName = '' OR CategoryName LIKE '%' + @CategoryName + '%')
	ORDER BY CategoryID
END
GO
