CREATE PROCEDURE [dbo].[SpCategoriaInsertar]
	@CategoryName nvarchar(15),
	@Description ntext,
	@Picture image,
	@CategoryID int output
AS
BEGIN
	INSERT INTO Categories(CategoryName, Description, Picture)
	Values (
		@CategoryName,
		@Description,
		@Picture
	);
	SET @CategoryID = SCOPE_IDENTITY();
END
