CREATE PROCEDURE [dbo].[SpCategoriaObtener]
	@top100 Bit = 0
AS
BEGIN
	Set nocount on;
	If @top100 = 1
		SELECT * FROM Categories Order by CategoryID Desc
	Else
		SELECT TOP 20 * FROM Categories Order by CategoryID Desc
END
GO
