CREATE PROCEDURE [dbo].[SpClienteActualizar]
	@Id nchar(5),
	@Compañia nvarchar(40),
	@Contacto nvarchar(30),
	@Titulo nvarchar(30),
	@Domicilio nvarchar(60),
	@Ciudad nvarchar(15),		
	@Region nvarchar(15),
	@CodigoP nvarchar(10),
	@Pais nvarchar(15),
	@Telefono nvarchar(24),
	@Fax nvarchar(24),
	@RowVersion binary(8)
AS
BEGIN
	SET NOCOUNT ON;
	-- Verificar si existe el empleado
    IF NOT EXISTS (SELECT 1 FROM Customers WHERE CustomerID = @Id)
    BEGIN
        RETURN -1; -- No existe el empleado
    END
	UPDATE Customers 
	SET CompanyName = @Compañia,
		ContactName = @Contacto,
		ContactTitle = @Titulo,
		Address = @Domicilio,
		City = @Ciudad,
