CREATE PROCEDURE [dbo].[SpEmpleadoActualizar]
	@Id int,
	@Nombres nvarchar(10),
	@Apellidos nvarchar(20),
	@Titulo nvarchar(30),
	@TitCortesia nvarchar(25),
	@FNacimiento datetime,
	@FContratacion datetime,
	@Domicilio nvarchar(60),
	@Ciudad nvarchar(15),		
	@Region nvarchar(15),
	@CodigoP nvarchar(10),
	@Pais nvarchar(15),
	@Telefono nvarchar(24),
	@Extension nvarchar(4),
	@Notas ntext,
	@Reportaa int,
	@Foto image,
	@RowVersion binary(8)
AS
BEGIN
	SET NOCOUNT ON;
	-- Verificar si existe el empleado
    IF NOT EXISTS (SELECT 1 FROM Employees WHERE EmployeeID = @Id)
    BEGIN
        RETURN -1; -- No existe el empleado
    END
	UPDATE Employees 
	SET	FirstName=@Nombres,
		LastName=@Apellidos,
		Title=@Titulo,
		TitleOfCourtesy=@TitCortesia,
		BirthDate=@FNacimiento,
		HireDate=@FContratacion,
		Address=@Domicilio,
		City=@Ciudad,
		Region=@Region,
		PostalCode=@CodigoP,
		Country=@Pais,
		HomePhone=@Telefono,
		Extension=@Extension,
		Notes=@Notas,
		ReportsTo=@Reportaa,
		--Photo=@Foto
		Photo = CASE 
                WHEN @Id <= 9 THEN Photo  -- conserva la foto existente
                ELSE @Foto                -- actualiza con el parámetro
                END
	WHERE  EmployeeID = @Id AND RowVersion = @RowVersion;
	DECLARE @rows int = @@ROWCOUNT;
	IF @rows = 0
        RETURN -2; -- Modificado por otro usuario
    ELSE
        RETURN @rows; -- Éxito
END
GO
