/****** Object:  StoredProcedure [dbo].[SpProductoBuscar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpProductoBuscar]
	@IdIni int,
	@IdFin int,
	@Producto nvarchar(40),
	@Categoria int,
	@Proveedor int
AS
BEGIN
	SET NOCOUNT ON;
	SELECT 
		p.ProductID,
		p.ProductName,
		p.SupplierID,
		p.CategoryID,
		p.QuantityPerUnit,
		p.UnitPrice,
		p.UnitsInStock,
		p.UnitsOnOrder,
		p.ReorderLevel,
		p.Discontinued,

		s.SupplierID,
		s.CompanyName,

		c.CategoryID,
		c.CategoryName,
		c.Description
	FROM Products p
	LEFT OUTER JOIN Categories c ON p.CategoryID = c.CategoryID
	LEFT OUTER JOIN Suppliers s ON p.SupplierID = s.SupplierID
	WHERE
	(@IdIni = 0 OR p.ProductID BETWEEN @IdIni AND @IdFin) AND 
	(@Producto = '' OR p.ProductName LIKE '%' + @Producto + '%') AND
	(@Categoria = 0 OR p.CategoryID = @Categoria ) AND
	(@Proveedor = 0 OR p.SupplierID = @Proveedor)
	ORDER BY p.ProductID DESC;
END
GO
/****** Object:  StoredProcedure [dbo].[SpProductoBuscarV2]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Este procedimiento evoluciono a SpProductosBuscarV3 donde se hace lo mismo pero de una manera menos verbosa
CREATE PROCEDURE [dbo].[SpProductoBuscarV2]
    @IdIni INT,
    @IdFin INT,
    @Producto VARCHAR(40),
    @Categoria INT,
    @Proveedor INT,
    @OrdenadoPor VARCHAR(255),
    @AscDesc VARCHAR(4)
AS
BEGIN
    SET NOCOUNT ON;
    SELECT
        Products.ProductID,
        Products.ProductName,
        Products.QuantityPerUnit,
        Products.UnitPrice,
        Products.UnitsInStock,
        Products.UnitsOnOrder,
        Products.ReorderLevel,
        Products.Discontinued,
        Categories.CategoryName,
        Categories.Description,
        Suppliers.CompanyName,
        Categories.CategoryID,
        Suppliers.SupplierID
    FROM Products
    LEFT JOIN Categories ON Products.CategoryID = Categories.CategoryID
    LEFT JOIN Suppliers ON Products.SupplierID = Suppliers.SupplierID
    WHERE
        ( @IdIni = 0 OR Products.ProductID BETWEEN @IdIni AND @IdFin )
        AND ( @Producto = '' OR Products.ProductName LIKE '%' + @Producto + '%' )
        AND ( @Categoria = 0 OR Products.CategoryID = @Categoria )
        AND ( @Proveedor = 0 OR Products.SupplierID = @Proveedor )
    ORDER BY
        /* ProductID */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'PRODUCTID' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.ProductID END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'PRODUCTID' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.ProductID END DESC,

        /* ProductName */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'PRODUCTNAME' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.ProductName END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'PRODUCTNAME' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.ProductName END DESC,

        /* QuantityPerUnit */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'QUANTITYPERUNIT' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.QuantityPerUnit END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'QUANTITYPERUNIT' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.QuantityPerUnit END DESC,

        /* UnitPrice */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'UNITPRICE' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.UnitPrice END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'UNITPRICE' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.UnitPrice END DESC,

        /* UnitsInStock */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'UNITSINSTOCK' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.UnitsInStock END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'UNITSINSTOCK' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.UnitsInStock END DESC,

        /* UnitsOnOrder */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'UNITSONORDER' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.UnitsOnOrder END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'UNITSONORDER' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.UnitsOnOrder END DESC,

        /* ReorderLevel */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'REORDERLEVEL' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.ReorderLevel END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'REORDERLEVEL' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.ReorderLevel END DESC,

        /* Discontinued */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'DISCONTINUED' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Products.Discontinued END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'DISCONTINUED' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Products.Discontinued END DESC,

        /* CategoryName */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'CATEGORYNAME' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Categories.CategoryName END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'CATEGORYNAME' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Categories.CategoryName END DESC,

        /* CategoryID */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'CATEGORYID' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Categories.CategoryID END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'CATEGORYID' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Categories.CategoryID END DESC,

        /* CompanyName (Supplier) */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'COMPANYNAME' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Suppliers.CompanyName END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'COMPANYNAME' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Suppliers.CompanyName END DESC,

        /* SupplierID */
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'SUPPLIERID' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'ASC' THEN Suppliers.SupplierID END ASC,
        CASE WHEN UPPER(LTRIM(RTRIM(@OrdenadoPor))) = 'SUPPLIERID' AND UPPER(LTRIM(RTRIM(@AscDesc))) = 'DESC' THEN Suppliers.SupplierID END DESC,

        /* Fallback order */
		/* Si no se define un campo y un orden valido a los anteriores se devuelve por default el siguiente orden */
        Products.ProductID DESC;
END;
GO
/****** Object:  StoredProcedure [dbo].[SpProductoBuscarV3]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Este procedimiento hace lo mismo que SpProductosBuscarV2 pero de una manera menos verbosa
CREATE PROCEDURE [dbo].[SpProductoBuscarV3]
    @IdIni INT,
    @IdFin INT,
    @Producto VARCHAR(40),
    @Categoria INT,
    @Proveedor INT,
    @OrdenadoPor VARCHAR(255),
    @AscDesc VARCHAR(4)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @sql NVARCHAR(MAX);
    DECLARE @params NVARCHAR(MAX);

    SET @sql = N'
        SELECT
            Products.ProductID,
            Products.ProductName,
            Products.QuantityPerUnit,
            Products.UnitPrice,
            Products.UnitsInStock,
            Products.UnitsOnOrder,
            Products.ReorderLevel,
            Products.Discontinued,
            Categories.CategoryName,
            Categories.Description,
            Suppliers.CompanyName,
            Categories.CategoryID,
            Suppliers.SupplierID
        FROM Products
        LEFT JOIN Categories ON Products.CategoryID = Categories.CategoryID
        LEFT JOIN Suppliers ON Products.SupplierID = Suppliers.SupplierID
        WHERE
            ( @IdIni = 0 OR Products.ProductID BETWEEN @IdIni AND @IdFin )
            AND ( @Producto = '''' OR Products.ProductName LIKE ''%'' + @Producto + ''%'' )
            AND ( @Categoria = 0 OR Products.CategoryID = @Categoria )
            AND ( @Proveedor = 0 OR Products.SupplierID = @Proveedor )
    ';

    -- Validar parámetros de ordenamiento para evitar SQL Injection
    IF UPPER(LTRIM(RTRIM(@OrdenadoPor))) NOT IN (
        'PRODUCTID','PRODUCTNAME','QUANTITYPERUNIT','UNITPRICE','UNITSINSTOCK',
        'UNITSONORDER','REORDERLEVEL','DISCONTINUED','CATEGORYNAME','CATEGORYID',
        'COMPANYNAME','SUPPLIERID'
    )
        SET @OrdenadoPor = 'PRODUCTID';

    IF UPPER(LTRIM(RTRIM(@AscDesc))) NOT IN ('ASC','DESC')
        SET @AscDesc = 'DESC';

    SET @sql = @sql + N' ORDER BY ' + @OrdenadoPor + N' ' + @AscDesc;

    SET @params = N'@IdIni INT, @IdFin INT, @Producto VARCHAR(40), @Categoria INT, @Proveedor INT';

    EXEC sp_executesql @sql, @params,
        @IdIni=@IdIni, @IdFin=@IdFin, @Producto=@Producto,
        @Categoria=@Categoria, @Proveedor=@Proveedor;
END;
GO
/****** Object:  StoredProcedure [dbo].[SpProductoBuscarV4]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpProductoBuscarV4]
    @IdIni INT,
    @IdFin INT,
    @Producto VARCHAR(40),
    @Categoria INT,
    @Proveedor INT,
    @OrdenadoPor VARCHAR(255),
    @AscDesc VARCHAR(4)
AS
BEGIN
    SET NOCOUNT ON;

    -- Validar columna de ordenamiento (lista blanca)
    IF UPPER(@OrdenadoPor) NOT IN (
        'PRODUCTID','PRODUCTNAME', 'QUANTITYPERUNIT','UNITPRICE','UNITSINSTOCK', 
		'UNITSONORDER', 'REORDERLEVEL', 'DISCONTINUED',
        'CATEGORYNAME','COMPANYNAME'
    )
        SET @OrdenadoPor = 'PRODUCTID'; -- fallback seguro, valor por default

    -- Validar dirección ASC/DESC, por default es ASC
    SET @AscDesc = CASE WHEN UPPER(@AscDesc) = 'DESC' THEN 'DESC' ELSE 'ASC' END;

    DECLARE @sql NVARCHAR(MAX) = N'
    SELECT
        Products.ProductID,
        Products.ProductName,
        Products.QuantityPerUnit,
        Products.UnitPrice,
        Products.UnitsInStock,
        Products.UnitsOnOrder,
        Products.ReorderLevel,
        Products.Discontinued,
        Categories.CategoryName,
        Categories.Description,
        Suppliers.CompanyName,
        Categories.CategoryID,
        Suppliers.SupplierID
    FROM Products
    LEFT JOIN Categories ON Products.CategoryID = Categories.CategoryID
    LEFT JOIN Suppliers ON Products.SupplierID = Suppliers.SupplierID';

    DECLARE @where NVARCHAR(MAX) = N'';

    IF @IdIni <> 0 AND @IdFin <> 0
        SET @where += N' AND Products.ProductID BETWEEN @IdIni AND @IdFin';

    IF @Producto <> ''
        SET @where += N' AND Products.ProductName LIKE ''%'' + @Producto + ''%''';

    IF @Categoria <> 0
        SET @where += N' AND Products.CategoryID = @Categoria';

    IF @Proveedor <> 0
        SET @where += N' AND Products.SupplierID = @Proveedor';

    -- Si hay condiciones, agregamos WHERE
    IF LEN(@where) > 0
        SET @sql += N' WHERE ' + STUFF(@where, 1, 5, ''); -- quita el primer "AND"

    -- Orden dinámico validado
    SET @sql += N' ORDER BY ' + QUOTENAME(@OrdenadoPor) + N' ' + @AscDesc;

    EXEC sp_executesql
        @sql,
        N'@IdIni INT, @IdFin INT, @Producto VARCHAR(40), @Categoria INT, @Proveedor INT',
        @IdIni, @IdFin, @Producto, @Categoria, @Proveedor;
END;
GO
/****** Object:  StoredProcedure [dbo].[SpProductoEliminar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpProductoEliminar]
	@ProductID int,
	@RowVersion binary(8)
AS
BEGIN
	SET NOCOUNT ON;
	-- Verificar si existe el producto
    IF NOT EXISTS (SELECT 1 FROM Products WHERE ProductID = @ProductID)
    BEGIN
        RETURN -1; -- No existe el producto
    END
	DELETE Products 
	WHERE  ProductID = @ProductID AND RowVersion = @RowVersion;
	DECLARE @rows int = @@ROWCOUNT;
	IF @rows = 0
        RETURN -2; -- Modificado por otro usuario
    ELSE
        RETURN @rows; -- Éxito
END
GO
