CREATE PROCEDURE [dbo].[SpProductoObtener]
	@top100 Bit = 0
AS
BEGIN
	SET NOCOUNT ON;
	If @top100 = 1
		SELECT 
			p.ProductID,
			p.ProductName,
			p.QuantityPerUnit,
			p.UnitPrice,
			p.UnitsInStock,
			p.UnitsOnOrder,
			p.ReorderLevel,
			p.Discontinued,

			s.SupplierID,
			s.CompanyName,

			c.CategoryID,
			c.CategoryName,
			c.Description
		FROM Products p
		LEFT OUTER JOIN Categories c ON p.CategoryID = c.CategoryID
		LEFT OUTER JOIN Suppliers s ON p.SupplierID = s.SupplierID
		ORDER BY p.ProductID DESC;
	Else
		SELECT TOP 20
			p.ProductID,
			p.ProductName,
			p.QuantityPerUnit,
			p.UnitPrice,
			p.UnitsInStock,
			p.UnitsOnOrder,
			p.ReorderLevel,
			p.Discontinued,

			s.SupplierID,
			s.CompanyName,

			c.CategoryID,
			c.CategoryName,
			c.Description
		FROM Products p
		LEFT OUTER JOIN Categories c ON p.CategoryID = c.CategoryID
		LEFT OUTER JOIN Suppliers s ON p.SupplierID = s.SupplierID
		ORDER BY p.ProductID DESC;
END
GO
