CREATE PROCEDURE [dbo].[SpProveedorActualizar]
	@SupplierId int,
	@CompanyName nvarchar(40),
	@ContactName nvarchar(30),
	@ContactTitle nvarchar(30),
	@Address nvarchar(60),
	@City nvarchar(15),		
	@Region nvarchar(15),
	@PostalCode nvarchar(10),
	@Country nvarchar(15),
	@Phone nvarchar(24),
	@Fax nvarchar(24),
	@RowVersion binary(8)
AS
BEGIN
	SET NOCOUNT ON;
	-- Verificar si existe el proveedor
    IF NOT EXISTS (SELECT 1 FROM Suppliers WHERE SupplierID = @SupplierId)
    BEGIN
        RETURN -1; -- No existe el proveedor
    END
	UPDATE Suppliers 
	SET CompanyName = @CompanyName,
		ContactName = @ContactName,
		ContactTitle = @ContactTitle,
		Address = @Address,
		City = @City,
		Region = @Region,
		PostalCode = @PostalCode,
		Country = @Country,
		Phone = @Phone,
		Fax = @Fax	
	WHERE  SupplierId = @SupplierId AND RowVersion = @RowVersion;
	DECLARE @rows int = @@ROWCOUNT;
	IF @rows = 0
        RETURN -2; -- Modificado por otro usuario
    ELSE
        RETURN @rows; -- Éxito
END
GO
