CREATE PROCEDURE [dbo].[SpProveedorBuscar]
	@IdIni int,
	@IdFin int,
	@CompanyName nvarchar(40),
	@ContactName nvarchar(30),
	@Address nvarchar(60),
	@City nvarchar(15),
	@Region nvarchar(15),
	@PostalCode nvarchar(10),
	@Country nvarchar(15),
	@Phone nvarchar(24),
	@Fax nvarchar(24)
AS
BEGIN
	SELECT *
	FROM Suppliers
	WHERE
	(@IdIni = 0 OR SupplierID BETWEEN @IdIni AND @IdFin) AND
	(@CompanyName = '' OR CompanyName LIKE '%' + @CompanyName + '%') AND
	(@ContactName = '' OR ContactName LIKE '%' + @ContactName + '%') AND
	(@Address = '' OR Address LIKE '%' + @Address + '%') AND
	(@City = '' OR City LIKE '%' + @City + '%') AND
	(@Region = '' OR Region LIKE '%' + @Region + '%') AND
	(@PostalCode = '' OR PostalCode LIKE '%' + @PostalCode + '%') AND
	(@Country = '' OR Country LIKE '%' + @Country + '%') AND
	(@Phone = '' OR Phone LIKE '%' + @Phone + '%') AND
	(@Fax = '' OR Fax LIKE '%' + @Fax + '%')
	ORDER BY SupplierID
END
