/****** Object:  StoredProcedure [dbo].[SpUsuarioActualizar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpUsuarioActualizar]
    @Id INT,
    @Paterno VARCHAR(50),
    @Materno VARCHAR(50),
    @Nombres VARCHAR(80),
    @Usuario VARCHAR(20),
    @Password VARCHAR(64),
    @FechaModificacion DATETIME,
    @Estatus TINYINT,
    @RowVersion BINARY(8) OUTPUT -- se pasa el valor actual de la fila
AS
BEGIN
    SET NOCOUNT ON;

    -- Verificar si existe el usuario
    IF NOT EXISTS (SELECT 1 FROM Usuarios WHERE Id = @Id)
    BEGIN
        RETURN -1; -- No existe el usuario
    END

    -- Intentar actualizar con control de concurrencia
    UPDATE Usuarios
    SET
        Paterno = NULLIF(@Paterno, ''),
        Materno = NULLIF(@Materno, ''),
        Nombres = @Nombres,
        Usuario = @Usuario,
        Password = @Password,
        FechaModificacion = @FechaModificacion,
        Estatus = @Estatus
    WHERE Id = @Id AND RowVersion = @RowVersion;

    DECLARE @rows INT = @@ROWCOUNT;

    IF @rows = 0
        RETURN -2; -- No se modificó (otro usuario cambió la fila)
    ELSE
	BEGIN
        -- Obtener el nuevo RowVersion generado por SQL Server
        SELECT @RowVersion = RowVersion
        FROM Usuarios
        WHERE Id = @Id;

        RETURN @rows; -- Éxito, devuelve número de filas afectadas
    END
END;
