/****** Object:  StoredProcedure [dbo].[SpUsuarioEliminar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpUsuarioEliminar]
    @Id INT,
    @RowVersion BINARY(8)
AS
BEGIN
    SET NOCOUNT ON;

    -- Verificar si existe el usuario
    IF NOT EXISTS (SELECT 1 FROM Usuarios WHERE Id = @Id)
    BEGIN
        RETURN -1; -- No existe el usuario
    END

    BEGIN TRY
        BEGIN TRANSACTION;

            -- Primero eliminar permisos relacionados
            DELETE FROM Permisos WHERE UsuarioId = @Id;
			DECLARE @permRows INT = @@ROWCOUNT;

            -- Luego eliminar el usuario con control de concurrencia
            DELETE FROM Usuarios 
            WHERE Id = @Id AND RowVersion = @RowVersion;
			DECLARE @userRows INT = @@ROWCOUNT;

            IF @userRows = 0
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -2; -- Modificado por otro usuario
            END

        COMMIT TRANSACTION;

        RETURN @userRows + @permRows; -- Éxito
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;

        RETURN -99; -- Error inesperado
    END CATCH
END
GO
