CREATE PROCEDURE [dbo].[SpUsuarioInsertar]
    @Id INT OUTPUT,
    @Paterno VARCHAR(50),
    @Materno VARCHAR(50),
    @Nombres VARCHAR(80),
    @Usuario VARCHAR(20),
    @Password VARCHAR(64),
    @FechaCaptura DATETIME,
    @FechaModificacion DATETIME,
    @Estatus TINYINT, 
	@RowVersion BINARY(8) OUTPUT
AS
BEGIN
    INSERT INTO Usuarios
        (Paterno, Materno, Nombres, Usuario, Password, FechaCaptura, FechaModificacion, Estatus)
    VALUES (
        NULLIF(@Paterno, ''),
        NULLIF(@Materno, ''),
        @Nombres,
        @Usuario,
        @Password,
        @FechaCaptura,
        @FechaModificacion,
        @Estatus
    );
    SET @Id = SCOPE_IDENTITY();
	SELECT @RowVersion = RowVersion
    FROM Usuarios
    WHERE Id = @Id;
END;
