CREATE PROCEDURE [dbo].[SpVentaActualizar]
	@OrderID int,
	@CustomerID nchar(5),
	@EmployeeID int,
	@OrderDate datetime,
	@RequiredDate datetime,
	@ShippedDate datetime,
	@ShipVia int,
	@Freight money, 
	@ShipName nvarchar(40),
	@ShipAddress nvarchar(60),
	@ShipCity nvarchar(15),
	@ShipRegion nvarchar(15),
	@ShipPostalCode nvarchar(10),
	@ShipCountry nvarchar(15),
	@RowVersion binary(8) output
AS
BEGIN
	IF NOT EXISTS (SELECT 1 FROM Orders WHERE OrderID = @OrderID)
		RETURN -1; -- No existe la venta
	BEGIN TRY
		BEGIN TRANSACTION
			UPDATE [Orders]
			SET
				[CustomerID] = @CustomerID,
				[EmployeeID] = @EmployeeID,
				[OrderDate] = @OrderDate,
				[RequiredDate] = @RequiredDate,
				[ShippedDate] = @ShippedDate,
				[ShipVia] = @ShipVia,
				[Freight] = @Freight,
				[ShipName] = @ShipName,
				[ShipAddress] = @ShipAddress,
				[ShipCity] = @ShipCity,
				[ShipRegion] = @ShipRegion,
				[ShipPostalCode] = @ShipPostalCode,
				[ShipCountry] = @ShipCountry
			WHERE
				OrderID = @OrderID AND RowVersion = @RowVersion;
			DECLARE @rows int = @@ROWCOUNT;
			IF @rows = 0
			BEGIN
				ROLLBACK TRANSACTION
				RETURN -2; -- Modificado por otro usuario
			END
			-- devolver el nuevo rowversion
			SELECT @RowVersion = RowVersion
			FROM Orders
			WHERE OrderID = @OrderID;

			COMMIT TRANSACTION
			RETURN 1 -- Éxito
	END TRY
    BEGIN CATCH
		IF @@TRANCOUNT > 0
			ROLLBACK TRANSACTION;
        -- Manejo de error genérico
        RETURN -99; -- Código de error genérico
    END CATCH
END
GO
/****** Object:  StoredProcedure [dbo].[SpVentaBuscar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentaBuscar]
	@IdIni int,
	@IdFin int,
	@Cliente nvarchar(40),
	@FVenta bit,
	@FVentaNull bit,
	@FVentaIni datetime,
	@FVentaFin datetime,
	@FRequerido bit,
	@FRequeridoNull bit,
	@FRequeridoIni datetime,
	@FRequeridoFin datetime,
	@FEnvio bit,
	@FEnvioNull bit,
	@FEnvioIni datetime,
	@FEnvioFin datetime,
	@Empleado nvarchar(31),
	@CompañiaT nvarchar(40),
	@Dirigidoa nvarchar(40)
AS
BEGIN
	SELECT DISTINCT o.OrderID, 
			c.CustomerID, 
			c.CompanyName As CustomerCompanyName, 
			c.ContactName, 
			e.EmployeeID, 
			LastName, 
			e.FirstName,
			o.OrderDate, 
			o.RequiredDate, 
			o.ShippedDate,
			s.ShipperID, 
			s.CompanyName AS ShipperCompanyName, 
			o.Freight, 
			o.ShipName, 
			o.ShipAddress, 
			o.ShipCity, 
			o.ShipRegion, 
			o.ShipPostalCode, 
			o.ShipCountry,
			o.RowVersion
		FROM Orders o 
		INNER JOIN Customers c ON o.CustomerID = c.CustomerID 
		INNER JOIN Employees e ON o.EmployeeID = e.EmployeeID 
		INNER JOIN Shippers s ON o.ShipVia = s.ShipperID 
	WHERE
		(@IdIni = 0 OR o.OrderID BETWEEN @IdIni AND @IdFin)
        AND (@Cliente = '' OR c.CompanyName LIKE '%' + @Cliente + '%')
        -- Rango semiabierto para OrderDate
        AND (@FVenta = 0 OR (o.OrderDate >= @FVentaIni AND o.OrderDate < @FVentaFin))
        AND (@FVentaNull = 0 OR o.OrderDate IS NULL)
        -- Rango semiabierto para RequiredDate
        AND (@FRequerido = 0 OR (o.RequiredDate >= @FRequeridoIni AND o.RequiredDate < @FRequeridoFin))
        AND (@FRequeridoNull = 0 OR o.RequiredDate IS NULL)
        -- Rango semiabierto para ShippedDate
        AND (@FEnvio = 0 OR (o.ShippedDate >= @FEnvioIni AND o.ShippedDate < @FEnvioFin))
        AND (@FEnvioNull = 0 OR o.ShippedDate IS NULL)
        AND (@Empleado = '' OR e.LastName + ' ' + e.FirstName LIKE '%' + @Empleado + '%')
        AND (@CompañiaT = '' OR s.CompanyName LIKE '%' + @CompañiaT + '%')
        AND (@Dirigidoa = '' OR o.ShipName LIKE '%' + @Dirigidoa + '%')
	ORDER BY o.OrderID DESC
END
GO
/****** Object:  StoredProcedure [dbo].[SpVentaDetalleActualizar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- versión del procedimiento con concurrencia optimista, pero ahora diferenciando explícitamente 
-- si el fallo fue porque el registro (de Orders o OrderDetails) fue modificado 
-- (RowVersion ya no coincide) o porque fue eliminado (ya no existe)
CREATE PROCEDURE [dbo].[SpVentaDetalleActualizar]
    @OrderID INT,
    @ProductID INT,
    @Quantity SMALLINT,
    @Discount real,
    @VentaDetalleRowVersion BINARY(8),
    @VentaRowVersion BINARY(8)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @OrderRowsAffected INT = 0;
    DECLARE @QuantityOld INT = 0;
    DECLARE @Diferencia INT = 0;
    DECLARE @DetalleExiste BIT;
	DECLARE @StockActual INT;
    DECLARE @NuevoStock INT;

    BEGIN TRY
        -- Validaciones iniciales
		IF NOT EXISTS (SELECT 1 FROM [Orders] WHERE OrderID = @OrderID)
            RETURN -3; -- No existe la orden
        IF NOT EXISTS (SELECT 1 FROM [Order Details] WHERE OrderID = @OrderID AND ProductID = @ProductID)
            RETURN -1; -- No existe el detalle
        
		-- Obtener cantidad anterior con concurrencia optimista
        SELECT @QuantityOld = Quantity
        FROM [Order Details]
        WHERE OrderID = @OrderID AND ProductID = @ProductID AND RowVersion = @VentaDetalleRowVersion;

        IF @@ROWCOUNT = 0
            RETURN -2; -- El detalle existe pero RowVersion cambió

        IF @QuantityOld IS NULL
            RETURN -5; -- Error de datos: Quantity en NULL

        BEGIN TRANSACTION;

        SET @Diferencia = @Quantity - @QuantityOld;

        -- Ajuste de inventario solo si cambia cantidad
        IF @Diferencia <> 0
        BEGIN
			-- Validar que el inventario no haya quedado negativo
			SELECT @StockActual = UnitsInStock FROM Products WHERE ProductID = @ProductID;
			-- Validar stock insuficiente (solo aplica si @Diferencia > 0, es decir, se incrementa cantidad)
            IF @Diferencia > 0 AND @StockActual < @Diferencia
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -6; -- Stock insuficiente
            END
			-- Calcular nuevo stock y validar overflow de SMALLINT
            SET @NuevoStock = COALESCE(@StockActual,0) - @Diferencia;
			-- Validar stock negativo (error de negocio)
			IF @NuevoStock < 0
			BEGIN
				ROLLBACK TRANSACTION;
				RETURN -8; -- Stock negativo no permitido (error de negocio)
			END
            IF @NuevoStock > 32767
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -7; -- Overflow de SMALLINT
            END

            UPDATE p
            SET UnitsInStock = @NuevoStock
            FROM Products p
            INNER JOIN [Order Details] od ON p.ProductID = od.ProductID
            WHERE od.OrderID = @OrderID
              AND od.ProductID = @ProductID
              AND od.RowVersion = @VentaDetalleRowVersion;

            IF @@ROWCOUNT = 0
            BEGIN
                SELECT @DetalleExiste = CASE WHEN EXISTS (SELECT 1 FROM [Order Details] WHERE OrderID = @OrderID AND ProductID = @ProductID) THEN 1 ELSE 0 END;
                ROLLBACK TRANSACTION;
                RETURN CASE WHEN @DetalleExiste = 1 THEN -2 ELSE -1 END;
            END
        END

        -- Actualizar detalle por si cambio discount
        UPDATE [Order Details]
        SET Quantity = @Quantity,
            Discount = @Discount
        WHERE OrderID = @OrderID
          AND ProductID = @ProductID
          AND RowVersion = @VentaDetalleRowVersion;

        IF  @@ROWCOUNT = 0
        BEGIN
            SELECT @DetalleExiste = CASE WHEN EXISTS (SELECT 1 FROM [Order Details] WHERE OrderID = @OrderID AND ProductID = @ProductID) THEN 1 ELSE 0 END;
            ROLLBACK TRANSACTION;
            RETURN CASE WHEN @DetalleExiste = 1 THEN -2 ELSE -1 END;
        END

        -- Forzar actualización de Orders para cambiar RowVersion
        UPDATE Orders
        SET ShipVia = ShipVia
        WHERE OrderID = @OrderID AND RowVersion = @VentaRowVersion;

        IF @@ROWCOUNT = 0
        BEGIN
            IF EXISTS (SELECT 1 FROM Orders WHERE OrderID = @OrderID)
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -4; -- Orden existe pero fue modificada
            END
            ELSE
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -3; -- Orden eliminada
            END
        END

        COMMIT TRANSACTION;
        RETURN 1; -- Éxito
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
        RETURN -99; -- Error inesperado
    END CATCH
END;
GO
/****** Object:  StoredProcedure [dbo].[SpVentaDetalleEliminar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- versión del procedimiento con concurrencia optimista, pero ahora diferenciando explícitamente 
-- si el fallo fue porque el registro (de Orders o OrderDetails) fue modificado 
-- (RowVersion ya no coincide) o porque fue eliminado (ya no existe)
CREATE PROCEDURE [dbo].[SpVentaDetalleEliminar]
    @OrderID INT,
    @ProductID INT,
    @VentaDetalleRowVersion binary(8),
    @VentaRowVersion binary(8)
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @OrderRowsAffected INT = 0;
	DECLARE @QuantityOld INT = 0;
    DECLARE @DetalleExiste BIT;
	DECLARE @StockActual INT;
    DECLARE @NuevoStock INT;

    BEGIN TRY
        -- Validaciones iniciales
        IF NOT EXISTS (SELECT 1 FROM [Orders] WHERE OrderID = @OrderID)
            RETURN -3; -- No existe la orden
		IF NOT EXISTS (SELECT 1 FROM [Order Details] WHERE OrderID = @OrderID AND ProductID = @ProductID)
            RETURN -1; -- No existe el detalle        

		-- Obtener cantidad anterior con concurrencia optimista
        SELECT @QuantityOld = Quantity
        FROM [Order Details]
        WHERE OrderID = @OrderID AND ProductID = @ProductID AND RowVersion = @VentaDetalleRowVersion;

        IF @@ROWCOUNT = 0
            RETURN -2; -- El detalle existe pero RowVersion cambió

        IF @QuantityOld IS NULL
            RETURN -5; -- Error de datos: Quantity en NULL

        BEGIN TRANSACTION;
		-- Ajuste de inventario: devolver productos al stock
		SELECT @StockActual = UnitsInStock FROM Products WHERE ProductID = @ProductID;
        -- Devolver productos al inventario
		 SET @NuevoStock = COALESCE(@StockActual,0) + @QuantityOld;
		 -- Validar stock negativo (error de negocio)
		 IF @NuevoStock < 0
		BEGIN
			ROLLBACK TRANSACTION;
			RETURN -8; -- Stock negativo no permitido
		END
		-- Validar overflow de SMALLINT (solo límite superior)
        IF @NuevoStock > 32767
        BEGIN
            ROLLBACK TRANSACTION;
            RETURN -7; -- Overflow de SMALLINT
        END

        UPDATE p
        SET p.UnitsInStock = @NuevoStock
        FROM Products p
        INNER JOIN [Order Details] od ON p.ProductID = od.ProductID
        WHERE od.OrderID = @OrderID
          AND od.ProductID = @ProductID
          AND od.RowVersion = @VentaDetalleRowVersion;

		IF @@ROWCOUNT = 0
            BEGIN
                SELECT @DetalleExiste = CASE WHEN EXISTS (SELECT 1 FROM [Order Details] WHERE OrderID = @OrderID AND ProductID = @ProductID) THEN 1 ELSE 0 END;
                ROLLBACK TRANSACTION;
                RETURN CASE WHEN @DetalleExiste = 1 THEN -2 ELSE -1 END;
            END

        -- Eliminar detalle
        DELETE FROM [Order Details]
        WHERE OrderID = @OrderID
          AND ProductID = @ProductID
          AND RowVersion = @VentaDetalleRowVersion;

		IF @@ROWCOUNT = 0
        BEGIN
            SELECT @DetalleExiste = CASE WHEN EXISTS (SELECT 1 FROM [Order Details] WHERE OrderID = @OrderID AND ProductID = @ProductID) THEN 1 ELSE 0 END;
            ROLLBACK TRANSACTION;
            RETURN CASE WHEN @DetalleExiste = 1 THEN -2 ELSE -1 END;
        END

        -- Forzar actualización de Orders para cambiar RowVersion y manejar concurrencia
        UPDATE Orders
        SET ShipVia = ShipVia
        WHERE OrderID = @OrderID AND RowVersion = @VentaRowVersion;

        IF @@ROWCOUNT = 0
        BEGIN
            IF EXISTS (SELECT 1 FROM Orders WHERE OrderID = @OrderID)
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -4; -- La orden existe pero fue modificada (RowVersion cambió)
            END
            ELSE
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -3; -- La orden ya no existe (fue eliminada)
            END
        END

        COMMIT TRANSACTION;
        RETURN 1;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
        RETURN -99; -- Error inesperado
    END CATCH
END;
GO
/****** Object:  StoredProcedure [dbo].[SpVentaDetalleInsertar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentaDetalleInsertar]
	@OrderID int,
	@ProductID int,
	@UnitPrice money,
	@Quantity smallint,
	@Discount real,
	@TasaIVA real,
	@VentaRowVersion BINARY(8) output
AS
BEGIN
	SET NOCOUNT ON;

	DECLARE @OrderRowsAffected INT = 0;
    DECLARE @StockActual INT;
    DECLARE @NuevoStock INT;

	
	BEGIN TRY
		-- Validaciones iniciales
		IF NOT EXISTS (SELECT 1 FROM [Orders] WHERE OrderID = @OrderID)
            RETURN -3; -- No existe la orden
        IF EXISTS (SELECT 1 FROM [Order Details] WHERE OrderID = @OrderID AND ProductID = @ProductID)
            RETURN -1; -- Ya existe el detalle

        BEGIN TRANSACTION;

		-- Obtener inventario actual
        SELECT @StockActual = UnitsInStock FROM Products WHERE ProductID = @ProductID;

        -- Validar stock insuficiente
        IF @StockActual IS NULL OR @StockActual < @Quantity
        BEGIN
            ROLLBACK TRANSACTION;
            RETURN -6; -- Stock insuficiente
        END

        -- Calcular nuevo stock
        SET @NuevoStock = COALESCE(@StockActual,0) - @Quantity;

        -- Validar stock negativo (error de negocio)
        IF @NuevoStock < 0
        BEGIN
            ROLLBACK TRANSACTION;
            RETURN -8; -- Stock negativo no permitido
        END

        -- Validar overflow de SMALLINT (solo límite superior)
        IF @NuevoStock > 32767
        BEGIN
            ROLLBACK TRANSACTION;
            RETURN -7; -- Overflow de SMALLINT
        END
			
		-- Actualizar UnitsInStock en Products (solo si alcanza)
        UPDATE Products
        SET UnitsInStock = @NuevoStock
        WHERE ProductID = @ProductId;          

        IF @@ROWCOUNT = 0
        BEGIN
            ROLLBACK TRANSACTION;
            RETURN -6; -- Stock insuficiente (no se pudo actualizar)
        END

		INSERT INTO [dbo].[Order Details]
            (OrderID, ProductID, UnitPrice, Quantity, Discount, TasaIVA)
        VALUES
            (@OrderID, @ProductID, @UnitPrice, @Quantity, @Discount, @TasaIVA);
		IF @@ROWCOUNT = 0
        BEGIN
            ROLLBACK TRANSACTION;
            RETURN -5; -- Error inesperado al insertar detalle
        END

		-- Forzar actualización de Orders para cambiar RowVersion
        UPDATE Orders
        SET ShipVia = ShipVia
        WHERE OrderID = @OrderID AND RowVersion = @VentaRowVersion;

        IF @@ROWCOUNT = 0
        BEGIN
            IF EXISTS (SELECT 1 FROM Orders WHERE OrderID = @OrderID)
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -4; -- Orden existe pero fue modificada
            END
            ELSE
            BEGIN
                ROLLBACK TRANSACTION;
                RETURN -3; -- Orden eliminada
            END
        END
		-- Obtener el nuevo RowVersion y devolverlo en el parámetro
		SELECT @VentaRowVersion = RowVersion
		FROM Orders
		WHERE OrderID = @OrderID;

		COMMIT TRANSACTION;
		RETURN 1; -- Éxito
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
        RETURN -99; -- Error inesperado
    END CATCH
END
GO
