CREATE PROCEDURE [dbo].[SpVentaDetalleObtenerPorVentaId]
	@OrderID int
AS
BEGIN
	SET NOCOUNT ON;
	SELECT 
		od.OrderID,
		od.ProductID,
		p.ProductName,
		od.UnitPrice,
		od.Quantity,
		od.Discount,
		od.RowVersion
	FROM [Order Details] AS od
	INNER JOIN Products AS p ON od.ProductID = p.ProductID
    WHERE OrderID = @OrderID
	ORDER BY od.RowVersion desc -- necesario para que el ultimo que se inserto sea el primero en que se lista en el DGV
