/****** Object:  StoredProcedure [dbo].[SpVentaEliminar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentaEliminar]
    @OrderID INT,
	@RowVersion binary(8),
	@ProductoExcede varchar(40) output
AS
BEGIN
    SET NOCOUNT ON;
	DECLARE @OrderRowsAffected INT = 0;
    BEGIN TRY
		IF NOT EXISTS (SELECT 1 FROM Orders WHERE OrderID = @OrderID)
		BEGIN
			RETURN -1; -- No existe la venta
		END

        BEGIN TRANSACTION;
			DECLARE @StockCheck TABLE (
				ProductID INT,
				ProductName NVARCHAR(40),
				UnitsInStock SMALLINT,
				Quantity SMALLINT,
				NuevoStock INT
			);

		-- Guardar resultados en tabla temporal
		INSERT INTO @StockCheck (ProductID, ProductName, UnitsInStock, Quantity, NuevoStock)
		SELECT p.ProductID,
			   p.ProductName,
			   p.UnitsInStock,
			   od.Quantity,
			   COALESCE(p.UnitsInStock,0) + od.Quantity AS NuevoStock
		FROM Products p
		INNER JOIN [Order Details] od ON p.ProductID = od.ProductID
		WHERE od.OrderID = @OrderID;

		-- Validar límites -- Validar stock negativo -- Validar overflow de SMALLINT
		SELECT TOP 1 @ProductoExcede = ProductName
		FROM @StockCheck
		WHERE NuevoStock < 0 OR NuevoStock > 32767;

		IF @ProductoExcede IS NOT NULL
		BEGIN
			ROLLBACK TRANSACTION;
			RETURN CASE 
					 WHEN EXISTS (SELECT 1 FROM @StockCheck WHERE NuevoStock < 0) THEN -8 -- Stock negativo no permitido
					 ELSE -7 -- Overflow de SMALLINT
				   END;
		END

        -- Devolver los productos al inventario
        UPDATE p
        SET p.UnitsInStock = p.UnitsInStock + od.Quantity
        FROM Products p
        INNER JOIN [Order Details] od ON p.ProductID = od.ProductID
        WHERE od.OrderID = @OrderID;

        -- Eliminar detalles del pedido
		-- Actualizar inventario en bloque
        DELETE FROM [Order Details]
        WHERE OrderID = @OrderID;

        -- Eliminar la orden con concurrencia optimista
        DELETE FROM Orders
        WHERE OrderID = @OrderID AND RowVersion = @RowVersion;
		SET @OrderRowsAffected = @@ROWCOUNT;
		IF @OrderRowsAffected = 0
		BEGIN
			ROLLBACK TRANSACTION;
			RETURN -2; -- La orden existe pero RowVersion cambió

		END
        COMMIT TRANSACTION;
		RETURN 1;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
		RETURN -99; -- Error inesperado
    END CATCH
END;
GO
/****** Object:  StoredProcedure [dbo].[SpVentaInsertar]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentaInsertar]
	@OrderID int output,
	@CustomerID nchar(5),
	@EmployeeID int,
	@OrderDate datetime,
	@RequiredDate datetime,
	@ShippedDate datetime,
	@ShipVia int,
	@Freight money, 
	@ShipName nvarchar(40),
	@ShipAddress nvarchar(60),
	@ShipCity nvarchar(15),
	@ShipRegion nvarchar(15),
	@ShipPostalCode nvarchar(10),
	@ShipCountry nvarchar(15),
	@RowVersion binary(8) output
AS
BEGIN
	BEGIN TRY
		BEGIN TRANSACTION
			-- Declaramos la tabla variable para capturar los valores del OUTPUT
			DECLARE @Inserted TABLE (
				OrderID int,
				RowVersion binary(8)
			);
			INSERT INTO [dbo].[Orders]
				([CustomerID]
				,[EmployeeID]
				,[OrderDate]
				,[RequiredDate]
				,[ShippedDate]
				,[ShipVia]
				,[Freight]
				,[ShipName]
				,[ShipAddress]
				,[ShipCity]
				,[ShipRegion]
				,[ShipPostalCode]
				,[ShipCountry])
			OUTPUT inserted.OrderID, inserted.RowVersion
			INTO @Inserted(OrderID, RowVersion)   -- tabla variable temporal
			VALUES
				(@CustomerId, 
				@EmployeeId, 
				@OrderDate, 
				@RequiredDate, 
				@ShippedDate, 
				@ShipVia, 
				@Freight, 
				@ShipName, 
				@ShipAddress, 
				@ShipCity, 
				@ShipRegion, 
				@ShipPostalCode, 
				@ShipCountry);
			 -- Asignamos los valores a los parámetros de salida
			SELECT TOP 1 
				@OrderID = OrderID,
				@RowVersion = RowVersion
			FROM @Inserted;
		COMMIT TRANSACTION
		RETURN 1; -- Exito
	END TRY
	BEGIN CATCH
        IF @@TRANCOUNT > 0
            ROLLBACK TRANSACTION;
        RETURN -99; -- Error inesperado en la base de datos
    END CATCH
END
GO
