SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentaObtener]
	@top100 Bit = 0 
AS
BEGIN
	SET NOCOUNT ON;
	IF @top100 = 1
		SELECT DISTINCT o.OrderID, 
			c.CustomerID, c.CompanyName As CustomerCompanyName, c.ContactName, 
			e.EmployeeID, LastName, e.FirstName,
			o.OrderDate, o.RequiredDate, o.ShippedDate,
			s.ShipperID, s.CompanyName AS ShipperCompanyName, 
			o.Freight, o.ShipName, o.ShipAddress, o.ShipCity, o.ShipRegion, o.ShipPostalCode, o.ShipCountry,
			o.RowVersion
		FROM Orders o 
		INNER JOIN Customers c ON o.CustomerID = c.CustomerID 
		INNER JOIN Employees e ON o.EmployeeID = e.EmployeeID 
		INNER JOIN Shippers s ON o.ShipVia = s.ShipperID 
		ORDER BY OrderID DESC;
	ELSE
		SELECT DISTINCT TOP 20 o.OrderID, 
			c.CustomerID, c.CompanyName As CustomerCompanyName, c.ContactName, 
			e.EmployeeID, LastName, e.FirstName,
			o.OrderDate, o.RequiredDate, o.ShippedDate,
			s.ShipperID, s.CompanyName AS ShipperCompanyName, 
			o.Freight, o.ShipName, o.ShipAddress, o.ShipCity, o.ShipRegion, o.ShipPostalCode, o.ShipCountry,
			o.RowVersion
		FROM Orders o 
		INNER JOIN Customers c ON o.CustomerID = c.CustomerID 
		INNER JOIN Employees e ON o.EmployeeID = e.EmployeeID 
		INNER JOIN Shippers s ON o.ShipVia = s.ShipperID 
		ORDER BY OrderID DESC;
END
GO
