CREATE PROCEDURE [dbo].[SpVentaObtenerPorId]
	@OrderID int
AS
BEGIN
	SET NOCOUNT ON;
	SELECT
		OrderID,
        Orders.CustomerID,
        Orders.EmployeeID,
        OrderDate,
        RequiredDate,
        ShippedDate,
        ShipVia,
        Freight,
        ShipName,
        ShipAddress,
        ShipCity,
        ShipRegion,
        ShipPostalCode,
        ShipCountry,
        Orders.RowVersion,
		Customers.CompanyName AS CustomerCompanyName, 
		Employees.LastName, 
		Employees.FirstName, 
		Shippers.CompanyName AS ShipperCompanyName,
		Orders.RowVersion
	FROM Orders LEFT OUTER JOIN
        Employees ON Orders.EmployeeID = Employees.EmployeeID LEFT OUTER JOIN
        Customers ON Orders.CustomerID = Customers.CustomerID LEFT OUTER JOIN
        Shippers ON Orders.ShipVia = Shippers.ShipperID    
	WHERE OrderID = @OrderID;
END
