/****** Object:  StoredProcedure [dbo].[SpVentasObtenerMensuales]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[SpVentasObtenerMensuales]
	@year int
AS
BEGIN
	SET NOCOUNT ON;
	SET LANGUAGE Spanish;
	WITH Meses AS (
		SELECT TOP (12) ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS Mes
		FROM sys.objects
	),
	VentasMensuales AS (
		SELECT 
			MONTH(o.OrderDate) AS Mes,
			SUM(CAST(od.UnitPrice AS DECIMAL(18,4)) * od.Quantity * (1 - CAST(od.Discount AS DECIMAL(18,4)))) AS Total
		FROM Orders o
		INNER JOIN [Order Details] od
			ON o.OrderID = od.OrderID
		WHERE YEAR(o.OrderDate) = @year
		GROUP BY MONTH(o.OrderDate)
	)
	SELECT 
		CAST(m.Mes AS INT) AS Mes,
		CAST(LEFT(DATENAME(MONTH, DATEFROMPARTS(@year, m.Mes, 1)),3) + '.' AS NVARCHAR(4)) AS NombreMes,
		CAST(ISNULL(v.Total, 0) AS DECIMAL(18,2)) AS Total
	FROM Meses m
	LEFT JOIN VentasMensuales v
		ON m.Mes = v.Mes
	ORDER BY m.Mes;
END;
GO
/****** Object:  StoredProcedure [dbo].[SpVentasObtenerMensualesPorAnios]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentasObtenerMensualesPorAnios]
    @years INT
AS
BEGIN
    SET NOCOUNT ON;
    SET LANGUAGE Spanish;

    WITH Meses AS
    (
        SELECT TOP (12)
            CAST(ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS INT) AS Mes
        FROM sys.objects
    ),
    Anios AS
    (
        SELECT TOP (@years)
            YEAR(OrderDate) AS Year
        FROM Orders
        GROUP BY YEAR(OrderDate)
        ORDER BY Year DESC
    ),
    VentasMensuales AS
    (
        SELECT 
            YEAR(o.OrderDate) AS Year,
            CAST(MONTH(o.OrderDate) AS INT) AS Mes,
            SUM(
                CAST(od.UnitPrice AS DECIMAL(18,4)) *
                od.Quantity *
                (1 - CAST(od.Discount AS DECIMAL(18,4)))
            ) AS Total
        FROM Orders o
        INNER JOIN [Order Details] od
            ON o.OrderID = od.OrderID
        GROUP BY 
            YEAR(o.OrderDate),
            MONTH(o.OrderDate)
    )
    SELECT 
        CAST(a.Year AS INT) AS Year,
        CAST(m.Mes AS INT) AS Mes,
        CAST(LEFT(DATENAME(MONTH, DATEFROMPARTS(a.Year, m.Mes, 1)),3) + '.' AS NVARCHAR(4)) AS NombreMes,
        CAST(ISNULL(v.Total, 0) AS DECIMAL(18,2)) AS Total
    FROM Anios a
    CROSS JOIN Meses m
    LEFT JOIN VentasMensuales v
        ON a.Year = v.Year
        AND m.Mes = v.Mes
    ORDER BY 
        a.Year DESC,
        m.Mes;
END
GO
/****** Object:  StoredProcedure [dbo].[SpVentasObtenerMensualesPorVendedoresPorAnio]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentasObtenerMensualesPorVendedoresPorAnio]
    @Anio INT
AS
BEGIN
    SET NOCOUNT ON;
    SET LANGUAGE Spanish;

    -- 12 meses
    WITH Meses AS
    (
        SELECT TOP (12)
            ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS Mes
        FROM sys.objects
    ),

    -- vendedores que vendieron ese año
    Vendedores AS
    (
        SELECT DISTINCT
            CONCAT(e.FirstName,' ',e.LastName) AS Vendedor
        FROM Employees e
        JOIN Orders o ON e.EmployeeID = o.EmployeeID
        WHERE YEAR(o.OrderDate) = @Anio
    ),

    -- ventas reales
    Ventas AS
    (
        SELECT 
            CONCAT(e.FirstName,' ',e.LastName) AS Vendedor,
            MONTH(o.OrderDate) AS Mes,
            SUM(od.UnitPrice * od.Quantity * (1 - od.Discount)) AS TotalVentas
        FROM Employees e
        JOIN Orders o ON e.EmployeeID = o.EmployeeID
        JOIN [Order Details] od ON o.OrderID = od.OrderID
        WHERE YEAR(o.OrderDate) = @Anio
        GROUP BY 
            e.FirstName,
            e.LastName,
            MONTH(o.OrderDate)
    )

    SELECT
        v.Vendedor,
        m.Mes,
        LEFT(DATENAME(MONTH, DATEFROMPARTS(@Anio, m.Mes, 1)),3) + '.' AS NombreMes,
        ROUND(ISNULL(ve.TotalVentas,0),2) AS TotalVentas
    FROM Vendedores v
    CROSS JOIN Meses m
    LEFT JOIN Ventas ve
        ON v.Vendedor = ve.Vendedor
        AND m.Mes = ve.Mes
    ORDER BY
        v.Vendedor,
        m.Mes;
END;
GO
/****** Object:  StoredProcedure [dbo].[SpVentasObtenerPorRangoFechaVenta]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentasObtenerPorRangoFechaVenta] 
	@FVentaIni DATETIME = NULL,
	@FVentaFin DATETIME = NULL
AS
BEGIN	
	SET NOCOUNT ON;
	SELECT 
		o.OrderDate,
		o.RequiredDate,
		o.ShippedDate,
		c.CompanyName,
		o.OrderID,
		o.Freight
	FROM Orders o
	INNER JOIN Customers c ON c.CustomerID = o.CustomerID
	WHERE 
		(
			@FVentaFin IS NULL AND @FVentaFin IS NULL AND o.OrderDate IS NULL
		)
		OR
		(
			@FVentaIni IS NOT NULL AND @FVentaFin IS NOT NULL
			AND o.OrderDate >= @FVentaIni
			AND o.OrderDate < @FVentaFin
		)
	ORDER BY o.OrderDate DESC, c.CompanyName;
END
GO
