/****** Object:  StoredProcedure [dbo].[SpVentasObtenerTopProductos]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentasObtenerTopProductos]
	@Cantidad int,
	@Anio int
AS
BEGIN
	SET NOCOUNT ON;
	SELECT TOP (@Cantidad)
		p.ProductName AS NombreProducto, 
		SUM(od.Quantity) AS CantidadVendida
	FROM [Order Details] AS od
	INNER JOIN Orders o ON od.OrderID = o.OrderID
	INNER JOIN Products AS p ON od.ProductID = p.ProductID
	WHERE (@anio = -1 OR YEAR(o.OrderDate) = @anio)
	GROUP BY p.ProductName
	ORDER BY CantidadVendida DESC, p.ProductName;
END;
GO
/****** Object:  StoredProcedure [dbo].[SpVentasObtenerTopProductosRpt]    Script Date: 25/03/2026 05:58:16 p. m. ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SpVentasObtenerTopProductosRpt]
	@Cantidad int,
	@Anio int
AS
BEGIN
	SET NOCOUNT ON;
	WITH Ventas AS
	(
		SELECT 
			p.ProductName,
			SUM(od.Quantity) AS CantidadVendida
		FROM [Order Details] od
		INNER JOIN Orders o ON od.OrderID = o.OrderID
		INNER JOIN Products p ON od.ProductID = p.ProductID
		WHERE (@Anio = -1 OR YEAR(o.OrderDate) = @Anio)
		GROUP BY p.ProductName
	)
	SELECT TOP (@Cantidad)
		ROW_NUMBER() OVER (ORDER BY CantidadVendida DESC, ProductName) AS Posicion,
		CONCAT(
			ROW_NUMBER() OVER (ORDER BY CantidadVendida DESC, ProductName),
			'.- ',
			ProductName
		) AS NombreProducto,
		CantidadVendida
	FROM Ventas
	ORDER BY CantidadVendida DESC, ProductName;
END
GO
